// ============================================
// ASSEMBLE VIDEO (POC)
// Fetches both source templates, merges elements,
// applies hardcoded test recipe, returns Creatomate source.
// ============================================

return (async () => {

// TODO: Move to n8n environment variable
const CREATOMATE_API_KEY = '754b059fc6f045ea9f16cbbdacd691bec27dec04525ad3a8a0d7cdf74136980793efce4b8aafee5312b097973d74b0a4';

const input = $json;

// ============================================
// HELPERS
// ============================================

function cloneElement(el) {
  return JSON.parse(JSON.stringify(el));
}

function findChild(composition, name) {
  if (!composition.elements) return null;
  return composition.elements.find(el => el.name === name) || null;
}

function generateId() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

function regenerateIds(el) {
  if (el.id) el.id = generateId();
  if (el.elements) el.elements.forEach(child => regenerateIds(child));
}

function injectAvatarUrls(variantComposition, videoUrl, maskUrl) {
  if (!variantComposition.elements) return;
  variantComposition.elements.forEach(child => {
    if (child.name === 'avatar-1') child.source = videoUrl;
    if (child.name === 'avatar-1-mask') child.source = maskUrl;
  });
}

function injectItemData(variantComposition, itemData) {
  if (!variantComposition.elements) return;
  variantComposition.elements.forEach(child => {
    if (child.name === 'item-photo') child.source = itemData.photo_url;
    if (child.name === 'title')      child.text   = itemData.title;
    if (child.name === 'price')      child.text   = itemData.price;
    if (child.name === 'mileage')    child.text   = itemData.mileage;
  });
}

function injectContactData(variantComposition, client) {
  if (!variantComposition.elements) return;
  variantComposition.elements.forEach(child => {
    if (child.name === 'business-name') child.text = client.business_name;
    if (child.name === 'address-1')     child.text = client.address_1;
    if (child.name === 'address-2')     child.text = client.address_2;
    if (child.name === 'website')       child.text = client.website;
    if (child.name === 'phone')         child.text = client.phone;
  });
}

function removeExitAnimation(el) {
  if (el.animations) {
    el.animations = el.animations.filter(a => a.time !== 'end');
  }
  if (el.elements) el.elements.forEach(child => removeExitAnimation(child));
}

// Show one variant inside a parent composition, hide all others
function selectVariant(parentEl, variantName) {
  if (!parentEl.elements) return null;
  const selected = parentEl.elements.find(el => el.name === variantName);
  if (selected) {
    selected.visible = true;
    parentEl.elements = [selected];
  }
  return selected;
}

// ============================================
// STEP 1: FETCH & MERGE TEMPLATES
// ============================================

async function fetchTemplateByTag(tag) {
  const list = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.creatomate.com/v1/templates?tags=' + encodeURIComponent(tag),
    headers: { 'Authorization': 'Bearer ' + CREATOMATE_API_KEY },
    json: true
  });
  if (!list || !list.length) throw new Error('No template found with tag: ' + tag);

  return await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.creatomate.com/v1/templates/' + list[0].id,
    headers: { 'Authorization': 'Bearer ' + CREATOMATE_API_KEY },
    json: true
  });
}

console.log('Fetching source templates...');
const trackTemplate = await fetchTemplateByTag('ALL-TRACKS_9:16');
const animTemplate  = await fetchTemplateByTag('ANIMATIONS-IN_9:16');
console.log('Templates fetched. Tracks: ' + trackTemplate.source.elements.length + ', Animations: ' + animTemplate.source.elements.length);

// Build element pools (top-level name -> element)
const trackPool = {};
trackTemplate.source.elements.forEach(el => {
  if (el.name) trackPool[el.name] = el;
});

const animPool = {};
animTemplate.source.elements.forEach(el => {
  if (el.name) animPool[el.name] = el;
});

console.log('Track pool: ' + Object.keys(trackPool).join(', '));
console.log('Anim pool: ' + Object.keys(animPool).length + ' animations');

// ============================================
// STEP 2: LOAD RECIPE FROM INPUT
// ============================================

// Scenes and recipes come from the Group Avatar Continuity node
const inputScenes = input.scenes;
const sceneRecipes = input._scene_recipes;
const avatarGroups = input._avatar_groups || [];

if (!inputScenes || !sceneRecipes) {
  throw new Error('Missing scenes or _scene_recipes from upstream node');
}

// Build recipe-compatible scene configs from scene recipes
const TEST_RECIPE = {
  ratio: '9:16',
  scenes: inputScenes.map(scene => {
    const recipe = sceneRecipes[scene.scene_slug];
    if (!recipe) throw new Error('Scene recipe not found: ' + scene.scene_slug);
    const def = recipe.definition;

    // Pick first allowed animation (or null)
    const animation = def.animation && def.animation.allowed && def.animation.allowed.length > 0
      ? def.animation.allowed[0]
      : null;

    return {
      name: scene.scene_slug,
      animation: animation,
      avatar: def.avatar && def.avatar.required ? true : null,
      avatar_variant: def.avatar && def.avatar.required ? def.avatar.default_variant : null,
      items: def.items ? def.items.track_variant : null,
      item_count: scene.items ? scene.items.length : 0,
      headline: scene.headline_text,
      caption_variant: def.caption_variant || null,
      logo: def.logo || null,
      contact: def.contact || null,
      // Pass through scene data for item injection
      _scene_items: scene.items || []
    };
  })
};

console.log('Recipe loaded: ' + TEST_RECIPE.scenes.length + ' scenes');

// ============================================
// STEP 3: CALCULATE SCENE TIMINGS
// ============================================

function calcSceneTimings(sceneAudios) {
  let cursor = 0;
  return sceneAudios.map(s => {
    const timing = {
      scene: s.scene,
      start: cursor,
      duration: s.duration,
      end: cursor + s.duration
    };
    cursor += s.duration;
    return timing;
  });
}

const sceneTimings = calcSceneTimings(input.scene_audios);
const totalDuration = sceneTimings[sceneTimings.length - 1].end;
console.log('Scene timings:', JSON.stringify(sceneTimings));
console.log('Total duration: ' + totalDuration + 's');

// ============================================
// STEP 4: PROCESS EACH SCENE
// ============================================

const outputElements = [];
// Use original template track numbers to preserve stacking order:
// 1=bg-image, 2=bg-music, 3=voiceover, 4=Item, 5=Avatar,
// 6=Contact, 7=Logo, 8=Headline, 9=Subtitles, 10=Thumbnail, 11=SafeAreas
// Animations go on top (track 20+)

for (const scene of TEST_RECIPE.scenes) {
  const timing = sceneTimings.find(t => t.scene === scene.name);
  if (!timing) throw new Error('No timing found for scene: ' + scene.name);

  console.log('Processing scene: ' + scene.name + ' (start=' + timing.start + ', duration=' + timing.duration + ')');

  // --- 4a. Animation track ---
  if (scene.animation) {
    if (!animPool[scene.animation]) throw new Error('Animation not found: ' + scene.animation);
    const el = cloneElement(animPool[scene.animation]);
    el.visible = true;
    el.time = timing.start;
    el.duration = 1.5;
    el.track = 20; // animations on top
    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Animation: ' + scene.animation + ' at t=' + timing.start);
  }

  // --- 4b. Avatar track ---
  if (scene.avatar && scene.avatar_variant) {
    // Find avatar URLs from the continuity group that contains this scene
    const avatarGroup = avatarGroups.find(g => g.scenes.includes(scene.name));
    const avatarData = avatarGroup ? {
      video_url: avatarGroup.avatar_video_url || input.scene_avatars?.find(a => a.scene === scene.name)?.video_url,
      mask_url: avatarGroup.avatar_mask_url || input.scene_avatars?.find(a => a.scene === scene.name)?.mask_url
    } : input.scene_avatars?.find(a => a.scene === scene.name);
    if (!avatarData || !avatarData.video_url) throw new Error('No avatar data for scene: ' + scene.name);
    if (!trackPool['Avatar']) throw new Error('Avatar not found in track pool');

    const el = cloneElement(trackPool['Avatar']);
    el.visible = true;
    el.time = timing.start;
    el.duration = timing.duration;
    el.track = 5; // Avatar layer from template

    // Select the variant and inject avatar URLs
    const variant = selectVariant(el, scene.avatar_variant);
    if (!variant) throw new Error('Avatar variant not found: ' + scene.avatar_variant);
    injectAvatarUrls(variant, avatarData.video_url, avatarData.mask_url);
    // Mute avatar videos — audio comes from voiceover track only
    if (variant.elements) {
      variant.elements.forEach(child => {
        if (child.name === 'avatar-1') child.volume = '0%';
      });
    }

    // Smart avatar transitions based on scene context
    const sceneIdx = TEST_RECIPE.scenes.indexOf(scene);
    const prevScene = sceneIdx > 0 ? TEST_RECIPE.scenes[sceneIdx - 1] : null;
    const nextScene = sceneIdx < TEST_RECIPE.scenes.length - 1 ? TEST_RECIPE.scenes[sceneIdx + 1] : null;
    const prevHasSameAvatar = prevScene && prevScene.avatar_variant === scene.avatar_variant;
    const nextHasSameAvatar = nextScene && nextScene.avatar_variant === scene.avatar_variant;

    if (!variant.animations) variant.animations = [];

    if (!prevHasSameAvatar) {
      variant.animations.push({
        time: 0,
        type: 'fade',
        easing: 'quadratic-out',
        duration: 0.5
      });
      console.log('    + Avatar fade IN (new/changed position)');
    }

    if (nextScene && !nextHasSameAvatar) {
      variant.animations.push({
        time: 'end',
        type: 'fade',
        easing: 'quadratic-out',
        duration: 0.5,
        reversed: true
      });
      console.log('    + Avatar fade OUT (leaving/changing position)');
    }

    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Avatar: ' + scene.avatar_variant + ' at t=' + timing.start);
  }

  // --- 4c. Item tracks (Nx cloning) ---
  if (scene.items && scene.item_count > 0) {
    const itemDuration = timing.duration / scene.item_count;

    for (let i = 0; i < scene.item_count; i++) {
      const itemData = scene._scene_items[i];
      if (!itemData) throw new Error('No item data for index ' + i);
      if (!trackPool['Item']) throw new Error('Item not found in track pool');

      const el = cloneElement(trackPool['Item']);
      el.visible = true;
      el.time = timing.start + (i * itemDuration);
      el.duration = itemDuration;
      el.track = 4; // Item layer from template

      // Select the item variant and inject data
      const variant = selectVariant(el, scene.items);
      if (!variant) throw new Error('Item variant not found: ' + scene.items);
      injectItemData(variant, itemData);

      // All items keep their enter/exit animations

      regenerateIds(el);
      outputElements.push(el);
      console.log('  + Item ' + (i + 1) + ': ' + itemData.title + ' at t=' + el.time + ' dur=' + itemDuration);
    }
  }

  // --- 4d. Headline tracks ---
  if (scene.headline && scene.headline.length > 0) {
    if (!trackPool['Headline']) throw new Error('Headline not found in track pool');
    const el = cloneElement(trackPool['Headline']);
    el.visible = true;
    el.time = timing.start;
    el.duration = timing.duration;
    el.track = 8; // Headline layer from template

    const positions = ['headline-top', 'headline-middle', 'headline-bottom'];
    scene.headline.forEach((text, idx) => {
      const child = findChild(el, positions[idx]);
      if (child) {
        child.text = text;
        child.visible = true;
      }
    });
    // Hide unused positions
    positions.slice(scene.headline.length).forEach(pos => {
      const child = findChild(el, pos);
      if (child) child.visible = false;
    });

    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Headline: ' + scene.headline.join(' | '));
  }

  // --- 4e. Caption track ---
  if (scene.caption_variant) {
    if (!trackPool['Subtitles']) throw new Error('Subtitles not found in track pool');
    const el = cloneElement(trackPool['Subtitles']);
    el.visible = true;
    el.time = timing.start;
    el.duration = timing.duration;
    el.track = 9; // Subtitles layer from template

    selectVariant(el, scene.caption_variant);
    // Set transcript source and fix duration on children
    if (el.elements) {
      el.elements.forEach(child => {
        // Override the template's 0.1s duration — match scene duration
        child.duration = timing.duration;
        if (input.full_audio_url) {
          // Real audio: use voiceover track as transcript source
          child.transcript_source = 'voiceover';
        } else {
          // POC mode: no real audio, use placeholder text
          delete child.transcript_source;
          delete child.transcript_effect;
          delete child.transcript_placement;
          delete child.transcript_color;
          delete child.transcript_maximum_length;
          child.text = '(captions here)';
        }
      });
    }

    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Captions: ' + scene.caption_variant);
  }

  // --- 4f. Logo track ---
  if (scene.logo) {
    if (!trackPool['Logo']) throw new Error('Logo not found in track pool');
    const el = cloneElement(trackPool['Logo']);
    el.visible = true;
    el.time = timing.start;
    el.duration = timing.duration;
    el.track = 7; // Logo layer from template

    if (scene.logo === 'square-logo') {
      const sq = findChild(el, 'square-logo');
      const hz = findChild(el, 'horizontal-logo');
      if (sq) { sq.visible = true;  sq.source = input.logos.square; }
      if (hz) { hz.visible = false; }
    } else {
      const sq = findChild(el, 'square-logo');
      const hz = findChild(el, 'horizontal-logo');
      if (hz) { hz.visible = true;  hz.source = input.logos.horizontal; }
      if (sq) { sq.visible = false; }
    }

    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Logo: ' + scene.logo);
  }

  // --- 4g. Contact track ---
  if (scene.contact) {
    if (!trackPool['Contact']) throw new Error('Contact not found in track pool');
    const el = cloneElement(trackPool['Contact']);
    el.visible = true;
    el.time = timing.start;
    el.duration = timing.duration;
    el.track = 6; // Contact layer from template

    const variant = selectVariant(el, scene.contact);
    if (variant) {
      injectContactData(variant, input.client);
    }

    regenerateIds(el);
    outputElements.push(el);
    console.log('  + Contact: ' + scene.contact);
  }

  // --- 4h. Per-scene background (overrides default) ---
  if (scene._scene_bg_url || (inputScenes[TEST_RECIPE.scenes.indexOf(scene)] && inputScenes[TEST_RECIPE.scenes.indexOf(scene)].background_url)) {
    const sceneBgUrl = scene._scene_bg_url || inputScenes[TEST_RECIPE.scenes.indexOf(scene)].background_url;
    if (sceneBgUrl && trackPool['background-image']) {
      const bgEl = cloneElement(trackPool['background-image']);
      bgEl.visible = true;
      bgEl.time = timing.start;
      bgEl.duration = timing.duration;
      bgEl.track = 1; // Same track as default bg — overlaps and covers it for this scene
      bgEl.source = sceneBgUrl;
      // Add fade transitions at boundaries
      bgEl.animations = [
        { time: 0, type: 'fade', easing: 'quadratic-out', duration: 0.5 },
        { time: 'end', type: 'fade', easing: 'quadratic-out', duration: 0.5, reversed: true }
      ];
      regenerateIds(bgEl);
      outputElements.push(bgEl);
      console.log('  + Scene background: ' + sceneBgUrl);
    }
  }
} // end for-each scene

// ============================================
// STEP 5: ADD BASE TRACKS
// ============================================

// Background image (track 1)
const bgEl = cloneElement(trackPool['background-image']);
bgEl.visible = true;
bgEl.time = 0;
bgEl.duration = totalDuration;
bgEl.track = 1;
if (input.background_image_url) bgEl.source = input.background_image_url;
regenerateIds(bgEl);

// Voiceover (track 3) - full TTS audio runs entire video
if (trackPool['voiceover'] && input.full_audio_url) {
  const voiceEl = cloneElement(trackPool['voiceover']);
  voiceEl.visible = true;
  voiceEl.time = 0;
  voiceEl.duration = totalDuration;
  voiceEl.track = 3;
  voiceEl.source = input.full_audio_url;
  regenerateIds(voiceEl);
  outputElements.unshift(voiceEl);
  console.log('  + Voiceover track: ' + input.full_audio_url);
}

// Background music (track 2)
const musicEl = cloneElement(trackPool['background-music']);
musicEl.visible = true;
musicEl.time = 0;
musicEl.duration = totalDuration;
musicEl.track = 2;
if (input.background_music_url) musicEl.source = input.background_music_url;
regenerateIds(musicEl);

// Insert base tracks at beginning (lowest layer)
outputElements.unshift(bgEl, musicEl);

console.log('Total elements: ' + outputElements.length);


// ============================================
// STEP 6: BUILD FINAL SOURCE
// ============================================

const finalSource = {
  output_format: 'mp4',
  width: 720,
  height: 1280,
  duration: totalDuration,
  elements: outputElements
};

console.log('Assembly complete. Duration: ' + totalDuration + 's, Elements: ' + outputElements.length);

return {
  json: {
    ...input,
    creatomate: { source: finalSource },
    _total_duration: totalDuration,
    _scene_timings: sceneTimings
  }
};

})();

