// Parse 11Labs response, calculate scene timings, upload audio
return (async () => {

const config = $('Prep TTS Request').first().json;
const response = $json;

const audioBase64 = response.audio_base64;
const alignment = response.alignment;
if (!alignment) throw new Error('No alignment data from ElevenLabs');

const chars = alignment.characters;
const starts = alignment.character_start_times_seconds;
const ends = alignment.character_end_times_seconds;
const audioDuration = ends[ends.length - 1];

console.log('Audio duration: ' + audioDuration.toFixed(2) + 's');

// Calculate scene boundaries using character positions
const scenes = config.test_scenes || [];
const slugs = config._video_recipe.scene_slugs;
let charPos = 0;
const sceneTimings = [];

for (let i = 0; i < scenes.length; i++) {
  const sceneText = scenes[i].audio_text;
  const startCharPos = charPos;
  const endCharPos = charPos + sceneText.length - 1;

  const startTime = starts[startCharPos] || 0;
  const endTime = ends[Math.min(endCharPos, ends.length - 1)] || audioDuration;

  sceneTimings.push({
    scene: slugs[i],
    start: startTime,
    end: endTime,
    duration: endTime - startTime
  });

  console.log('Scene ' + i + ' (' + slugs[i] + '): ' + startTime.toFixed(2) + 's - ' + endTime.toFixed(2) + 's (' + (endTime - startTime).toFixed(2) + 's)');
  charPos += sceneText.length + 1;
}

